let texto = "";
let chatId;
let type;
const triggerData = $('Telegram Trigger').first().json;

// Verifica se é um callback_query (botão inline)
if (triggerData.callback_query) {
  chatId = triggerData.callback_query.from.id;
  texto = triggerData.callback_query.data ?? "";
  type = "botao";

} else {
  chatId = triggerData.message.from.id;

  // Verifica se é uma foto
  if (triggerData.message.photo) {
    type = "foto";
    texto = triggerData.message.caption ?? "";

  } else {
    // Fluxo original: mensagem de texto ou áudio transcrito
    type = "texto";
    try {
      const transcribe = $('Transcrever Audio').all();
      if (transcribe.length > 0) {
        texto = transcribe[0].json.text;
      }
    } catch (e) {}

    if (!texto) {
      try {
        const telegram = $('Telegram Trigger').all();
        if (telegram.length > 0) {
          texto = telegram[0].json.message.text ?? "";
        }
      } catch (e) {}
    }
  }
}

return [
  {
    json: {
      id: chatId,
      text: texto,
      type: type
    }
  }
];

