const body = $input.first().json.body.content;

const PLACEHOLDER = '<<foto>>';
let startIndex = null;

for (const element of body) {
  if (!element.paragraph) continue;

  for (const el of element.paragraph.elements) {
    if (el.textRun && el.textRun.content.includes(PLACEHOLDER)) {
      const offsetDentroDoRun = el.textRun.content.indexOf(PLACEHOLDER);
      startIndex = el.startIndex + offsetDentroDoRun;
      break;
    }
  }

  if (startIndex !== null) break;
}

if (startIndex === null) throw new Error('Placeholder <<foto>> não encontrado no documento');

return [{ json: { startIndex, endIndex: startIndex + PLACEHOLDER.length } }];

